{"IncludesReferencedQueries":false,"RootFormulaText":"let
    // 1. Get your existing Master List (the one you currently edit)
    MasterList = #"Topics and KPI's All",

    // 2. Get the unique list of KPIs from your raw data (PN + RC combined)
    // Create a query that combines PN and RC first, then use it here
    AllData = #"Staging Query", 
    UniqueKPIs = Table.Distinct(Table.SelectColumns(AllData, {"Topic","Attributes","JoinKey","Data Format"})),

    // 3. Find only the KPIs that DO NOT exist in the MasterList
    // JoinKind.LeftAnti is the magic here: it keeps only rows from UniqueKPIs NOT found in MasterList
    NewKPIsOnly = Table.NestedJoin(UniqueKPIs, {"JoinKey"}, MasterList, {"JoinKey"}, "Check", JoinKind.LeftAnti),
    MissingKPIs = Table.ExpandTableColumn(NewKPIsOnly, "Check", {"Joinkey"}, {"Found"}),
    FilteredMissing = Table.SelectRows(MissingKPIs, each ([Found] = null)),

    // 4. Assign new IDs starting after your current Max ID
    MaxID = List.Max(MasterList[KPI ID]),
    AddIDs = Table.AddIndexColumn(FilteredMissing, "NewID", MaxID + 1, 1),

    // 5. Clean up columns to match your MasterList structure
    RenameColumns = Table.RenameColumns(AddIDs, {{"NewID", "KPI ID"}, {"Attributes", "KPI Name "}}),
