    #"Expanded Topic.1" = Table.ExpandTableColumn(#"Merge Dynamic Topic", "Topic.1", {"Topic ID"}, {"Topic ID"}),
    FinalNewKPIs = Table.SelectColumns(#"Expanded Topic.1", {"KPI ID", "Topic", "KPI Name ","Data Format","JoinKey","Topic ID"}),

    // 6. Combine the MasterList with the new "discovered" KPIs
    FullList = Table.Combine({MasterList, FinalNewKPIs}),
