{"IncludesReferencedQueries":false,"RootFormulaText":"let
    // 1. Reference your existing static Dim Topic table
    MasterList = #"Dim Topic",

    // 2. Get the unique list of Topics from your combined PN & RC data
    AllData = #"Staging Query", 
    UniqueTopics = Table.Distinct(Table.SelectColumns(AllData, {"Topic"})),

    // 3. Find Topics that are in the Data but MISSING from the MasterList
    // JoinKind.LeftAnti keeps only rows from UniqueTopics NOT found in MasterList
    NewTopicsOnly = Table.NestedJoin(UniqueTopics, {"Topic"}, MasterList, {"Topic"}, "Check", JoinKind.LeftAnti),

    // 4. Remove the join column and clean up
    MissingTopics = Table.RemoveColumns(NewTopicsOnly, {"Check"}),
    #"Filtered Rows" = Table.SelectRows(MissingTopics, each ([Topic] <> null)),

    // 5. Assign new IDs starting from the current Max ID + 1
    MaxID = List.Max(MasterList[Topic ID]),
    AddIDs = Table.AddIndexColumn(#"Filtered Rows", "Topic ID", MaxID + 1, 1),

    // 6. Combine the MasterList with the new topics
    // We re-order to match columns exactly before combining
    FinalList = Table.Combine({MasterList, Table.SelectColumns(AddIDs, {"Topic", "Topic ID"})})
in
    FinalList","ReferencedQueriesFormulaText":{}}

{"IncludesReferencedQueries":false,"RootFormulaText":"let
    // 1. Reference existing table
    MasterList = #"Dim Report Type",

    // 2. Get unique attributes from staging
    AllData = #"Staging Query", 
    UniqueReport = Table.Distinct(Table.SelectColumns(AllData, {"Attribute"})),

    // 3. Try to Fuzzy Match first 
    // We use a Threshold of 0.8 (adjust to 0.7 if it's too strict, 0.9 if too loose)
    FuzzyMatch = Table.FuzzyNestedJoin(
        UniqueReport, {"Attribute"}, 
        MasterList, {"Report Type"}, 
        "Check", 
        JoinKind.LeftOuter, 
        [IgnoreCase=true, IgnoreSpace=true, Threshold=0.8]
    ),

    // 4. Keep only the rows where no match was found (Table.IsEmpty)
    MissingReport = Table.SelectRows(FuzzyMatch, each Table.IsEmpty([Check])),

    // 5. Clean up columns to prepare for ID assignment
    // We take the "Attribute" column and rename it to "Report Type" so it matches the MasterList
    CleanMissing = Table.RenameColumns(Table.RemoveColumns(MissingReport, {"Check"}), {{"Attribute", "Report Type"}}),

    // 6. Assign new IDs starting from Max ID + 1
    MaxID = List.Max(MasterList[Report Type ID]),
    AddIDs = Table.AddIndexColumn(CleanMissing, "Report Type ID", MaxID + 1, 1),

    // 7. Combine the MasterList with the new rows
    FinalList = Table.Combine({MasterList, AddIDs})
in
    FinalList","ReferencedQueriesFormulaText":{}}
